var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"JPN":"イナの多次元お茶会","ENG":"Ina’s MulTEA-dimensional Party"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"EDEL_ESPR_CLB_003","text":{"KOREA":"차 더 마실 사람?","JPN":"みんな、お茶のおかわりはどう？","ENG":"Anyone up for another cup of tea?"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_CLB_003","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HOLY_KNIGHT_CLB_003","text":{"KOREA":"혹시, 이나. 레드 와인은 없어?","JPN":"イナ、レッドワインはないか？","ENG":"Hey, Ina. Do you have any red wine?"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_CLB_003","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"EDEL_ESPR_CLB_003","text":{"KOREA":"물론 있지. 칼리를 위해 사둔 게 있어. 곧 가져다 줄게.","JPN":"もちろんあるよ。カリオペのために買っておいたんだ。ちょっと持ってくるねー。","ENG":"Ah yes, Calli. I got one just for you. I’ll be right back."},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_CLB_003","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HOLY_KNIGHT_CLB_003","text":{"KOREA":"고마워, 이나!","JPN":"ありがとう、イナ！","ENG":"Oh. thanks, Ina!"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_CLB_003","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YOONA_CODEX_CLB_003","text":{"KOREA":"구라, 뭘 그렇게 찾아? 아까부터 꼬리밖에 안 보이잖아!","JPN":"ぐら、なにをそんなに探しているの？　さっきからしっぽしか見えないわよ？","ENG":"Gura, what are you looking for? Your tail tells me you’re up to something!"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"YOONA_CODEX_CLB_003","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"POLEARM_JUNIOR_CLB_003","text":{"KOREA":"음? 아, 응… 아무것도 아니야….","JPN":"うん？　あ、えっと……なんでもないよ……","ENG":"Hmm? Oh, umm… it's nothing…."},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_CLB_003","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HOLY_KNIGHT_CLB_003","text":{"KOREA":"살랑살랑 움직이는 꼬리 좀 봐! 꼬리를 잡고 산으로 던져 버리고 싶어!","JPN":"ゆらゆら揺れてるあのしっぽを見て！　しっぽを掴んであの山まで投げ飛ばしたくなるな！","ENG":"Look at that tail wiggling. Oh… Imma grab that tail and throw it over the mountain one day."},"stage":{"bg":"DORMITORY_2","slots":{"L":{"char_id":"YOONA_CODEX_CLB_003","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_CLB_003","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"YOONA_CODEX_CLB_003","text":{"KOREA":"아, 또 시작이야.","JPN":"はぁ、また始まった。","ENG":"Oh, here we go again."},"stage":{"bg":"DORMITORY_2","slots":{"L":{"char_id":"YOONA_CODEX_CLB_003","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_CLB_003","face":"UNIT_PRIDE"}}}},{"id":"L19_1","type":"dialog","speaker":"YOONA_CODEX_CLB_003","text":{"KOREA":"귀여운 사람들 볼 때마다 산으로 던져 버린대. 언젠가 너를 산으로 던질 사람도 분명 나타날 거야!","JPN":"いつもかわいい人見ると山に投げ飛ばすって言ってるわよね？　いつか君も投げ飛ばされる日が来るわよ！","ENG":"You always want to throw small people over mountains, maybe one should throw you for a change!"},"stage":{"bg":"DORMITORY_2","slots":{"L":{"char_id":"YOONA_CODEX_CLB_003","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_CLB_003","face":"UNIT_PRIDE"}}}},{"id":"L20_1","type":"dialog","speaker":"HOLY_KNIGHT_CLB_003","text":{"KOREA":"흥, 내가 그렇게 순순히 잡힐 줄 알아?","JPN":"ふん、俺がそう簡単に投げ飛ばされるもんか。","ENG":"Hmph. As if I’ll get caught that easily."},"stage":{"bg":"DORMITORY_2","slots":{"L":{"char_id":"YOONA_CODEX_CLB_003","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_CLB_003","face":"UNIT_PRIDE"}}}},{"id":"L21_1","type":"dialog","speaker":"YOONA_CODEX_CLB_003","text":{"KOREA":"내가 매처럼 순식간에 낚아채면 너도 별 수 없을걸?","JPN":"私が鷹のように君を搔っ攫ったら簡単に行けると思うけど？","ENG":"Unless you don’t have a reflex like a hawk like I do, you won’t stand a chance."},"stage":{"bg":"DORMITORY_2","slots":{"L":{"char_id":"YOONA_CODEX_CLB_003","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_CLB_003","face":"UNIT_PRIDE"}}}},{"id":"L22_1","type":"dialog","speaker":"HOLY_KNIGHT_CLB_003","text":{"KOREA":"하지만… 넌 닭이잖아.","JPN":"でも、お前は鷹じゃなくて鶏じゃん。","ENG":"But… but you are a chicken."},"stage":{"bg":"DORMITORY_2","slots":{"L":{"char_id":"YOONA_CODEX_CLB_003","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_CLB_003","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"YOONA_CODEX_CLB_003","text":{"KOREA":"아-앙?! 닭이 아니라 불사조거든!","JPN":"はっ、はぁ？　鶏じゃないわよ！　私はフェニックスよ？！","ENG":"What?! I’m not a chicken! I am a phoenix!"},"stage":{"bg":"DORMITORY_2","slots":{"L":{"char_id":"YOONA_CODEX_CLB_003","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HOLY_KNIGHT_CLB_003","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"HOLY_KNIGHT_CLB_003","text":{"KOREA":"그거나 그거나!","JPN":"そんな変わらないって。","ENG":"Same thing!"},"stage":{"bg":"DORMITORY_2","slots":{"L":{"char_id":"YOONA_CODEX_CLB_003","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HOLY_KNIGHT_CLB_003","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"EDEL_ESPR_CLB_003","text":{"KOREA":"자, 자. 다들 그만 싸워. 그리고 칼리, 여기 네가 주문한 레드 와인이야.","JPN":"はい、はい。喧嘩はもうおしまい。カリオペ、頼んでたワイン持って来たよ。","ENG":"Alright, you two. Calm down. And Calli, here is your glass of red wine."},"stage":{"bg":"DORMITORY_2","slots":{"L":{"char_id":"YOONA_CODEX_CLB_003","face":"UNIT_SERIOUS"},"C":{"char_id":"EDEL_ESPR_CLB_003","face":"UNIT_IDLE"},"R":{"char_id":"HOLY_KNIGHT_CLB_003","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"HOLY_KNIGHT_CLB_003","text":{"KOREA":"음, 와인 향이 좋네! 고마워 이나, 잘 마실게.","JPN":"お、いい香り！　ありがたくいただくよ！","ENG":"Mmm, the wine’s fragrance is so good! Thanks, Ina!"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_CLB_003","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HARIM_REBBIT_CLB_003","text":{"KOREA":"이나아아. 내 차는?","JPN":"イナー、アタシのお茶はまだ？","ENG":"INAAA- what about my tea?"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_CLB_003","face":"UNIT_IDLE"},"R":{"char_id":"HARIM_REBBIT_CLB_003","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"EDEL_ESPR_CLB_003","text":{"KOREA":"하하, 아메, 당연히 네 차도 가져왔지. 따라 줄게.","JPN":"はは…、もちろん持って来たよー。注いであげるね。","ENG":"Ahaha, I got yours as well, Ame. Lemme grab another cup."},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_CLB_003","face":"UNIT_LAUGH"},"R":{"char_id":"HARIM_REBBIT_CLB_003","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"HARIM_REBBIT_CLB_003","text":{"KOREA":"부탁해!","JPN":"ありがとう！","ENG":"Please!"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_CLB_003","face":"UNIT_LAUGH"},"R":{"char_id":"HARIM_REBBIT_CLB_003","face":"UNIT_LAUGH"}}}},{"id":"L39_1","type":"dialog","speaker":"EDEL_ESPR_CLB_003","text":{"KOREA":"한번 생각해 봤는데, 만약 주전자 속을 타임 리프시키면 계속해서 차를 따라 마실 수 있을까?","JPN":"考えてみたんだけどね、ティーポットの中の時間を巻き戻し続けたら無限にお茶が飲めるんじゃない？","ENG":"I just thought about this, but if we make the inside of the teapot to time leap, would we be able to infinitely pour out tea?"},"stage":{"bg":"DORMITORY_2","slots":{"L":{"char_id":"HARIM_REBBIT_CLB_003","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_CLB_003","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"HARIM_REBBIT_CLB_003","text":{"KOREA":"오옷, 흥미로운 질문이야. 그리고 그 질문에 답은, 물론 가능하다는 거!","JPN":"お！　興味深い質問だね！　答えはもちろん……可能だ！","ENG":"Oooh, that’s an interesting question. And the answer to your question is, yes, it is possible."},"stage":{"bg":"DORMITORY_2","slots":{"L":{"char_id":"HARIM_REBBIT_CLB_003","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"EDEL_ESPR_CLB_003","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"HARIM_REBBIT_CLB_003","text":{"KOREA":"하지만, 시간여행은 굉장히 조심해야 해.","JPN":"でもね、時間を巻き戻すのって結構注意を払う必要があるんだよ。","ENG":"Although, we need to be very careful when time traveling."},"stage":{"bg":"DORMITORY_2","slots":{"L":{"char_id":"HARIM_REBBIT_CLB_003","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EDEL_ESPR_CLB_003","face":"UNIT_IDLE"}}}}]`);export{e as default};